import 'package:flutter/material.dart'; import 'package:flutter_riverpod/flutter_riverpod.dart'; import '../../../../core/widgets/app_primary_button.dart'; import '../../../../core/widgets/app_snackbar.dart'; import '../../domain/entities/review.dart'; import '../providers/review_providers.dart'; import '../widgets/rating_selector.dart';
class SubmitReviewPage extends ConsumerStatefulWidget{final String sellerId,productId; final String? reviewId; const SubmitReviewPage({super.key,required this.sellerId,required this.productId,this.reviewId}); @override ConsumerState<SubmitReviewPage> createState()=>_SubmitReviewPageState();}
class _SubmitReviewPageState extends ConsumerState<SubmitReviewPage>{final comment=TextEditingController(); ReviewRating rating=ReviewRating.five; @override void dispose(){comment.dispose();super.dispose();} Future<void> submit() async{if(widget.reviewId==null){await ref.read(reviewControllerProvider.notifier).createReview(sellerId:widget.sellerId,productId:widget.productId,rating:rating,comment:comment.text);}else{await ref.read(reviewControllerProvider.notifier).updateReview(reviewId:widget.reviewId!,sellerId:widget.sellerId,productId:widget.productId,rating:rating,comment:comment.text);} if(!mounted)return; final st=ref.read(reviewControllerProvider); if(st.errorMessage!=null)return AppSnackbar.error(context,st.errorMessage!); AppSnackbar.success(context,'Review saved'); Navigator.pop(context);} @override Widget build(BuildContext context){final st=ref.watch(reviewControllerProvider); return Scaffold(appBar:AppBar(title:const Text('Review')),body:ListView(padding:const EdgeInsets.all(16),children:[RatingSelector(value:rating,onChanged:(v)=>setState(()=>rating=v)),TextField(controller:comment,minLines:4,maxLines:8,decoration:const InputDecoration(labelText:'Comment')),const SizedBox(height:16),AppPrimaryButton(label:'Submit',isLoading:st.isLoading,onPressed:submit)]));}}
